#include <stdio.h>
#include <string.h>
int main(){
    int T,N; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        scanf("%d",&N);
        int xorMask=0; char s[12];
        for(int i=0;i<N;++i){
            scanf("%s",s);
            int mask=0;
            for(int j=0;j<10;++j) if(s[j]=='1') mask|=(1<<j);
            xorMask^=mask;
        }
        int ans=__builtin_popcount(xorMask);
        printf("%d\n",ans);
    }
    return 0;
}

