const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  let xorMask = 0;
  for (let i = 0; i < N; ++i) {
    const s = input[idx++];
    const mask = parseInt(s, 2);
    xorMask ^= mask;
  }
  let cnt = 0;
  let x = xorMask;
  while (x) { cnt += x & 1; x >>= 1; }
  results.push(String(cnt));
}
console.log(results.join('\n'));
